  "protocol": "aap/0.1",
  "id": "url-shortener-service",
  "version": 1,
  "name": "edit",
  "content": [
    {
      "op": "insert_after",
      "target": {
        "type": "id",
        "value": "handlers"
      },
      "content": "func (s *Store) GetTopURLs(w http.ResponseWriter, r *http.Request) {
	limit := 10
	if l := r.URL.Query().Get("limit"); l != "" {
		fmt.Sscanf(l, "%d", &limit)
	}

	s.mu.RLock()
	var sorted []*URL
	for _, u := range s.urls {
		sorted = append(sorted, u)
	}
	s.mu.RUnlock()

	// Simple sort: most clicked first
	for i := 0; i < len(sorted); i++ {
		for j := i + 1; j < len(sorted); j++ {
			if sorted[j].Clicks > sorted[i].Clicks {
				sorted[i], sorted[j] = sorted[j], sorted[i]
			}
		}
	}

	if limit > len(sorted) {
		limit = len(sorted)
	}
	json.NewEncoder(w).Encode(sorted[:limit])
}
"
    },
    {
      "op": "insert_after",
      "target": {
        "type": "id",
        "value": "main-top-routes"
      },
      "content": "	mux.HandleFunc("GET /urls/top", store.GetTopURLs)"
    }
  ]
}
